//! Table-driven golden tests for the timestamp formatters.
//!
//! These replay fixtures generated by the reference JS in
//! `goldens/gen/timestamp_ref.mjs` (a DOM-/Intl-free reimplementation of the
//! EXACT `index.html` `formatMs`/`formatStamp`/`formatDuration`) and assert the
//! Rust port reproduces every string byte-for-byte — including JS arithmetic
//! quirks (`Math.floor`, sign-preserving `%`, `padStart`) on negative deltas and
//! the en-US 12-hour clock strings produced by `Intl`.
//!
//! Regenerate goldens: `node crates/silent-core/goldens/gen/timestamp_ref.mjs`.
#![allow(
    clippy::unwrap_used,
    clippy::expect_used,
    reason = "tests use unwrap/expect as the assertion mechanism (PRD lint config)"
)]

use serde::Deserialize;
use silent_core::timestamp::{format_ago, format_clock, format_duration, format_elapsed};
use std::path::PathBuf;

fn goldens_dir() -> PathBuf {
    PathBuf::from(env!("CARGO_MANIFEST_DIR")).join("goldens/timestamp")
}

fn load<T: for<'de> Deserialize<'de>>(name: &str) -> T {
    let path = goldens_dir().join(name);
    let bytes =
        std::fs::read(&path).unwrap_or_else(|e| panic!("read golden {}: {e}", path.display()));
    serde_json::from_slice(&bytes)
        .unwrap_or_else(|e| panic!("parse golden {}: {e}", path.display()))
}

#[derive(Deserialize)]
struct ElapsedFile {
    cases: Vec<ElapsedCase>,
}
#[derive(Deserialize)]
struct ElapsedCase {
    #[serde(rename = "tsMs")]
    ts_ms: i64,
    #[serde(rename = "startTime")]
    start_time: i64,
    expected: String,
}

#[test]
fn elapsed_matches_js() {
    let f: ElapsedFile = load("elapsed.json");
    assert!(!f.cases.is_empty(), "elapsed fixture is empty");
    for c in f.cases {
        let got = format_elapsed(c.ts_ms, c.start_time);
        assert_eq!(
            got, c.expected,
            "elapsed(ts={}, start={}) = {:?}, want {:?}",
            c.ts_ms, c.start_time, got, c.expected
        );
    }
}

