fn clock_matches_intl() {
    let f: ClockFile = load("clock.json");
    assert!(!f.cases.is_empty(), "clock fixture is empty");
    for c in f.cases {
        let got = format_clock(c.hour, c.minute);
        assert_eq!(
            got, c.expected,
            "clock(h={}, m={}) = {:?}, want {:?}",
            c.hour, c.minute, got, c.expected
        );
    }
}

